export function useGetOrderStats<TData = Awaited<ReturnType<typeof getOrderStats>>, TError = ErrorType<unknown>>(
  options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getOrderStats>>, TError, TData>, }

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getGetOrderStatsQueryOptions(options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







export const getUpdateOrderStatusUrl = (id: number,) => {




  return `/api/orders/${id}/status`
}

/**
 * @summary Update order status
 */
export const updateOrderStatus = async (id: number,
    orderStatusPatch: OrderStatusPatch, options?: RequestInit): Promise<Order> => {

  return customFetch<Order>(getUpdateOrderStatusUrl(id),
  {
    ...options,
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      orderStatusPatch,)
  }
);}




export const getUpdateOrderStatusMutationOptions = <TError = ErrorType<void>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof updateOrderStatus>>, TError,{id: number;data: BodyType<OrderStatusPatch>}, TContext>, }
): UseMutationOptions<Awaited<ReturnType<typeof updateOrderStatus>>, TError,{id: number;data: BodyType<OrderStatusPatch>}, TContext> => {

const mutationKey = ['updateOrderStatus'];
const {mutation: mutationOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof updateOrderStatus>>, {id: number;data: BodyType<OrderStatusPatch>}> = (props) => {
          const {id,data} = props ?? {};

          return  updateOrderStatus(id,data,)
        }






  return  { mutationFn, ...mutationOptions }}

    export type UpdateOrderStatusMutationResult = NonNullable<Awaited<ReturnType<typeof updateOrderStatus>>>
    export type UpdateOrderStatusMutationBody = BodyType<OrderStatusPatch>
    export type UpdateOrderStatusMutationError = ErrorType<void>

    /**
 * @summary Update order status
 */
export const useUpdateOrderStatus = <TError = ErrorType<void>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof updateOrderStatus>>, TError,{id: number;data: BodyType<OrderStatusPatch>}, TContext>, }
 ): UseMutationResult<
        Awaited<ReturnType<typeof updateOrderStatus>>,
        TError,
        {id: number;data: BodyType<OrderStatusPatch>},
        TContext
      > => {
      return useMutation(getUpdateOrderStatusMutationOptions(options));
    }

